#include "spec9.h"
int ac=0,fc=0,ff=0;struct Alias aliases[MAX_ALIASES];struct Function functions[MAX_FUNCTIONS];
void load_myshrc(){FILE*f=fopen(".myshrc","r");if(!f)return;char l[MAX_COMMAND_LENGTH],cfn[MAX_FUNCTION_NAME]="",fb[MAX_FUNCTION_BODY]="";int inf=0;while(fgets(l,sizeof(l),f)){trim_whitespace(l);if(l[0]=='#')continue;if(strncmp(l,"alias",5)==0){char*ns=l+5;char*eq=strchr(ns,'=');if(eq){*eq='\0';char*n=ns,*c=eq+1;trim_whitespace(n);trim_whitespace(c);if(ac<MAX_ALIASES){strncpy(aliases[ac].n,n,MAX_ALIAS_LENGTH-1);strncpy(aliases[ac].c,c,MAX_COMMAND_LENGTH-1);ac++;}}}else if(strncmp(l,"func",4)==0){char*fs=l+4;while(*fs==' ')fs++;char*fe=fs;while(*fe&&*fe!=' '&&*fe!='(')fe++;*fe='\0';strncpy(cfn,fs,MAX_FUNCTION_NAME-1);inf=1;fb[0]='\0';}else if(inf){if(strcmp(l,"}")==0){inf=0;if(fc<MAX_FUNCTIONS){strncpy(functions[fc].n,cfn,MAX_FUNCTION_NAME-1);strncpy(functions[fc].b,fb,MAX_FUNCTION_BODY-1);fc++;}}else{char*cs=strchr(l,'#');if(cs){*cs='\0';trim_whitespace(l);}if(strlen(l)>0){strcat(fb,l);strcat(fb,"\n");}}}}fclose(f);}
char*get_alias_command(char*n){for(int i=0;i<ac;i++)if(strcmp(trim_whitespace(aliases[i].n),n)==0)return aliases[i].c;return NULL;}
void exec_func(char*fn,char*arg){for(int i=0;i<fc;i++){if(strcmp(trim_whitespace(functions[i].n),fn)==0){char cmd[MAX_COMMAND_LENGTH];strcpy(cmd,trim_whitespace(functions[i].b));char*dp=strstr(cmd,"");while(dp){memmove(dp+strlen(arg),dp+2,strlen(dp+2)+1);memcpy(dp,arg,strlen(arg));dp=strstr(dp+strlen(arg),"");}char*ob=strchr(cmd,'{');char*cb=strrchr(cmd,'}');if(ob&&cb){memmove(cmd,ob+1,cb-ob-1);cmd[cb-ob-1]='\0';}trim_whitespace(cmd);char nc[4096];process_input(cmd,nc);and_input(nc);return;}}printf("Function %s not found.\n",fn);}
void mk_hop(char*c){char d[MAX_COMMAND_LENGTH];if(sscanf(c,"mk_hop %s",d)==1)exec_func("mk_hop",d);else printf("Usage: mk_hop <dir>\n");}
void hop_seek(char*c){char d[MAX_COMMAND_LENGTH];if(sscanf(c,"hop_seek %s",d)==1)exec_func("hop_seek",d);else printf("Usage: hop_seek <dir>\n");}
void handle_command(char*c,int fg){if(!ff){load_myshrc();ff=1;}char fw[MAX_ALIAS_LENGTH];sscanf(c,"%s",fw);char*ac=get_alias_command(fw);if(ac)execute_post_input(trim_whitespace(ac),fg);else execute_post_input(c,fg);}
